    create: true
    extension: "json"
    format: "json"
    fields:
      - {label: "Title", name: "title", widget: "string"}
      - {label: "Icon (FontAwesome class)", name: "icon", widget: "string"}
      - {label: "Description", name: "description", widget: "text"}

  - name: "experience"
    label: "Experience"
    file: "content/experience.json"
    fields:
      - label: "Experiences"
        name: "experiences"
        widget: "list"
        fields:
          - {label: "Role", name: "role", widget: "string"}
          - {label: "Organization", name: "organization", widget: "string"}
          - {label: "Period", name: "period", widget: "string"}
          - {label: "Description", name: "description", widget: "text"}
          - {label: "Type", name: "type", widget: "select", options: ["leadership", "academic"]}

  - name: "projects"
    label: "Projects"
    file: "content/projects.json"
    fields:
      - label: "Projects"
        name: "projects"
        widget: "list"
        fields:
          - {label: "Title", name: "title", widget: "string"}
          - {label: "Description", name: "description", widget: "text"}
          - {label: "Image", name: "image", widget: "image"}
          - {label: "Tags", name: "tags", widget: "list"}
          - {label: "External Link", name: "link", widget: "string", required: false}
          - {label: "GitHub Link", name: "github", widget: "string", required: false}

import React, { useState, useEffect, useRef } from 'react';
import { 
  Profile, 
  ResearchInterest, 
  Experience, 
  Project, 
  SkillCategory, 
  Achievement, 
  PortfolioData 
} from './types';

// Fallback data in case JSON files aren't available (common on first deploy)
const FALLBACK_DATA: PortfolioData = {
  profile: {
    name: "Md Atik Sheikh",
    position: "Secretary, IEEE RAS RUSB",
    university: "University of Rajshahi",
    bio: "Passionate researcher focused on Robotics and Automation. Leader at IEEE Robotics and Automation Society Student Branch, dedicated to fostering innovation and technical excellence in the student community.",
    image: "https://picsum.photos/seed/atik/400/400",
    email: "atik.sheikh@ieee.org",
    github: "https://github.com",
    linkedin: "https://linkedin.com"
  },
  research: [
    { title: "Robotics & Automation", icon: "fa-robot", description: "Exploring autonomous control systems and swarm robotics for industrial applications." },
    { title: "Artificial Intelligence", icon: "fa-brain", description: "Applying deep learning techniques to computer vision problems in manufacturing." },
    { title: "Embedded Systems", icon: "fa-microchip", description: "Designing high-efficiency power management systems for IoT devices." }
  ],
  experience: [
    { role: "Secretary", organization: "IEEE RAS RUSB", period: "2023 - Present", description: "Leading administrative operations and coordinating robotics workshops for 500+ members.", type: "leadership" },
    { role: "Undergraduate Researcher", organization: "CSE, University of Rajshahi", period: "2022 - Present", description: "Researching in autonomous navigation systems and human-robot interaction.", type: "academic" }
  ],
  projects: [
    { title: "Autonomous Explorer Drone", description: "A customized hexacopter for indoor autonomous navigation.", image: "https://picsum.photos/seed/drone/800/450", tags: ["ROS", "Python"], github: "https://github.com" },
    { title: "IEEE RAS Dashboard", description: "Centralized management system for branch activities.", image: "https://picsum.photos/seed/dash/800/450", tags: ["React", "Firebase"], link: "https://google.com" }
  ],
  skills: [
    { category: "Languages", items: ["C++", "Python", "JavaScript"] },
    { category: "Tools", items: ["ROS", "React", "Arduino"] }
  ],
  achievements: [
    { title: "Best Student Volunteer", date: "2023", issuer: "IEEE Bangladesh Section" }
  ]
};

const RevealOnScroll: React.FC<{ children: React.ReactNode; className?: string }> = ({ children, className = "" }) => {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('active');
        }
      });
    }, { threshold: 0.1 });

    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);

  return <div ref={ref} className={`reveal ${className}`}>{children}</div>;
};

const SectionTitle: React.FC<{ title: string; subtitle?: string }> = ({ title, subtitle }) => (
  <div className="mb-12 text-center">
    <h2 className="text-3xl md:text-4xl font-extrabold text-slate-900 dark:text-white mb-4">
      {title}
    </h2>
    {subtitle && <p className="text-brand font-semibold tracking-wider uppercase text-sm">{subtitle}</p>}
    <div className="w-20 h-1.5 bg-brand mx-auto mt-4 rounded-full"></div>
  </div>
);

const App: React.FC = () => {
  const [data, setData] = useState<PortfolioData>(FALLBACK_DATA);
  const [darkMode, setDarkMode] = useState(true);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const fetchFile = async (path: string) => {
          const res = await fetch(path);
          if (!res.ok) throw new Error(`Failed to fetch ${path}`);
          return res.json();
        };

        const [profile, research, experience, projects, skills, achievements] = await Promise.all([
          fetchFile('/content/profile.json'),
          fetchFile('/content/research.json'),
          fetchFile('/content/experience.json'),
          fetchFile('/content/projects.json'),
          fetchFile('/content/skills.json'),
          fetchFile('/content/achievements.json'),
        ]);

        setData({ profile, research, experience, projects, skills, achievements });
      } catch (err) {
        console.warn("Using fallback data as some content files were not found.");
        setData(FALLBACK_DATA);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="h-screen w-screen flex items-center justify-center bg-slate-50 dark:bg-slate-950">
        <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-b-4 border-brand"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen selection:bg-brand/30">
      {/* Background Decor */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none -z-10">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-brand/10 dark:bg-brand/5 blur-[120px] rounded-full animate-pulse-slow"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-brand/10 dark:bg-brand/5 blur-[120px] rounded-full animate-pulse-slow"></div>
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/grid-me.png')] opacity-[0.03] dark:opacity-[0.1]"></div>
      </div>

      {/* Navbar */}
      <nav className="fixed top-0 w-full z-50 px-4 md:px-8 py-4">
        <div className="max-w-7xl mx-auto glass rounded-2xl px-6 py-3 flex items-center justify-between shadow-xl">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-brand rounded-lg flex items-center justify-center text-white font-bold">A</div>
            <span className="font-bold text-xl tracking-tight hidden sm:block">Atik Sheikh</span>
          </div>

          <div className="hidden md:flex items-center gap-8">
            {['About', 'Research', 'Experience', 'Projects', 'Contact'].map(item => (
              <a 
                key={item} 
                href={`#${item.toLowerCase()}`} 
                className="text-sm font-medium hover:text-brand transition-colors text-slate-600 dark:text-slate-300"
              >
                {item}
              </a>
            ))}
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setDarkMode(!darkMode)}
              className="p-2 rounded-xl glass hover:bg-slate-200 dark:hover:bg-slate-800 transition-all text-slate-600 dark:text-slate-300"
            >
              {darkMode ? <i className="fas fa-sun"></i> : <i className="fas fa-moon"></i>}
            </button>
            <button 
              className="md:hidden p-2 text-slate-600 dark:text-slate-300"
              onClick={() => setIsMenuOpen(!isMenuOpen)}
            >
              <i className={`fas ${isMenuOpen ? 'fa-times' : 'fa-bars'} text-xl`}></i>
            </button>
          </div>
        </div>

        {/* Mobile Menu */}
        {isMenuOpen && (
          <div className="md:hidden absolute top-24 left-4 right-4 glass rounded-2xl p-6 shadow-2xl flex flex-col gap-4 animate-in fade-in slide-in-from-top-4">
            {['About', 'Research', 'Experience', 'Projects', 'Contact'].map(item => (
              <a 
                key={item} 
                href={`#${item.toLowerCase()}`} 
                onClick={() => setIsMenuOpen(false)}
                className="text-lg font-medium p-2 border-b border-slate-200 dark:border-slate-800"
              >
                {item}
              </a>
            ))}
          </div>
        )}
      </nav>

      {/* Hero Section */}
      <section id="about" className="pt-32 pb-20 px-6">
        <div className="max-w-7xl mx-auto grid md:grid-cols-2 gap-12 items-center">
          <div className="order-2 md:order-1 text-center md:text-left">
            <RevealOnScroll>
              <span className="inline-block px-4 py-1.5 rounded-full bg-brand/10 text-brand text-sm font-bold mb-6">
                IEEE ROBOTICS & AUTOMATION SOCIETY
              </span>
              <h1 className="text-5xl md:text-7xl font-extrabold mb-6 bg-clip-text text-transparent bg-gradient-to-r from-slate-900 via-brand to-brand-dark dark:from-white dark:to-brand-light">
                {data.profile.name}
              </h1>
              <p className="text-xl md:text-2xl text-slate-600 dark:text-slate-400 mb-8 font-medium">
                {data.profile.position} <br />
                <span className="text-slate-500 text-lg">{data.profile.university}</span>
              </p>
              <p className="text-lg text-slate-600 dark:text-slate-400 mb-10 max-w-xl leading-relaxed">
                {data.profile.bio}
              </p>
              <div className="flex flex-wrap gap-4 justify-center md:justify-start">
                <a href="#contact" className="px-8 py-4 bg-brand hover:bg-brand-dark text-white rounded-2xl font-bold transition-all shadow-lg shadow-brand/25">
                  Get In Touch
                </a>
                <a href={data.profile.github} target="_blank" className="px-8 py-4 glass hover:bg-slate-100 dark:hover:bg-slate-800 rounded-2xl font-bold transition-all">
                  View GitHub
                </a>
              </div>
            </RevealOnScroll>
          </div>
          <div className="order-1 md:order-2 flex justify-center">
            <RevealOnScroll className="relative">
              <div className="absolute inset-0 bg-brand/20 blur-[80px] rounded-full animate-pulse"></div>
              <img 
                src={data.profile.image} 
                alt={data.profile.name}
                className="w-64 h-64 md:w-80 md:h-80 rounded-[3rem] object-cover border-4 border-white dark:border-slate-800 shadow-2xl animate-float relative z-10"
              />
            </RevealOnScroll>
          </div>
        </div>
      </section>

      {/* Research Section */}
      <section id="research" className="py-20 px-6 bg-slate-100/50 dark:bg-slate-900/50">
        <div className="max-w-7xl mx-auto">
          <SectionTitle title="Research Interests" subtitle="Driving Innovation" />
          <div className="grid md:grid-cols-3 gap-8">
            {data.research.map((item, idx) => (
              <RevealOnScroll key={idx} className="h-full">
                <div className="glass p-8 rounded-[2rem] h-full hover:scale-[1.02] transition-transform flex flex-col items-center text-center">
                  <div className="w-16 h-16 bg-brand/10 rounded-2xl flex items-center justify-center text-brand text-3xl mb-6">
                    <i className={`fas ${item.icon}`}></i>
                  </div>
                  <h3 className="text-xl font-bold mb-4">{item.title}</h3>
                  <p className="text-slate-600 dark:text-slate-400 leading-relaxed">
                    {item.description}
                  </p>
                </div>
              </RevealOnScroll>
            ))}
          </div>
        </div>
      </section>

      {/* Experience Section */}
      <section id="experience" className="py-20 px-6">
        <div className="max-w-4xl mx-auto">
          <SectionTitle title="Experience & Leadership" subtitle="Academic Path" />
          <div className="space-y-8">
            {data.experience.map((exp, idx) => (
              <RevealOnScroll key={idx}>
                <div className="glass p-8 rounded-3xl relative overflow-hidden group">
                  <div className="absolute top-0 right-0 p-6 opacity-10 group-hover:opacity-20 transition-opacity">
                    <i className={`fas ${exp.type === 'leadership' ? 'fa-users' : 'fa-graduation-cap'} text-6xl`}></i>
                  </div>
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-4">
                    <div>
                      <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{exp.role}</h3>
                      <p className="text-brand font-semibold">{exp.organization}</p>
                    </div>
                    <span className="px-4 py-1 rounded-full bg-slate-200 dark:bg-slate-800 text-sm font-bold text-slate-600 dark:text-slate-400 whitespace-nowrap self-start md:self-center">
                      {exp.period}
                    </span>
                  </div>
                  <p className="text-slate-600 dark:text-slate-400 leading-relaxed">
                    {exp.description}
                  </p>
                </div>
              </RevealOnScroll>
            ))}
          </div>
        </div>
      </section>

      {/* Projects Section */}
      <section id="projects" className="py-20 px-6 bg-slate-100/50 dark:bg-slate-900/50">
        <div className="max-w-7xl mx-auto">
          <SectionTitle title="Technical Projects" subtitle="Building the Future" />
          <div className="grid md:grid-cols-2 gap-10">
            {data.projects.map((proj, idx) => (
              <RevealOnScroll key={idx}>
                <div className="glass overflow-hidden rounded-[2.5rem] group hover:shadow-2xl transition-all duration-500">
                  <div className="relative overflow-hidden h-64">
                    <img 
                      src={proj.image} 
                      alt={proj.title} 
                      className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900 to-transparent opacity-60"></div>
                    <div className="absolute bottom-6 left-6 flex gap-2 flex-wrap">
                      {proj.tags.map(tag => (
                        <span key={tag} className="px-3 py-1 bg-white/20 backdrop-blur-md text-white text-xs font-bold rounded-lg border border-white/20">
                          {tag}
                        </span>
                      ))}
                    </div>
                  </div>
                  <div className="p-8">
                    <h3 className="text-2xl font-bold mb-4">{proj.title}</h3>
                    <p className="text-slate-600 dark:text-slate-400 mb-6 line-clamp-2">
                      {proj.description}
