                    <i className="fas fa-award text-2xl"></i>
                  </div>
                  <div>
                    <h4 className="text-xl font-bold">{award.title}</h4>
                    <p className="text-slate-500 dark:text-slate-400">{award.issuer} • {award.date}</p>
                  </div>
                </RevealOnScroll>
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* Contact Section */}
      <section id="contact" className="py-20 px-6 bg-brand dark:bg-brand-dark overflow-hidden relative">
        <div className="absolute inset-0 opacity-10">
          <div className="absolute top-1/2 left-1/4 w-96 h-96 bg-white rounded-full blur-[100px]"></div>
          <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-white rounded-full blur-[100px]"></div>
        </div>
        <div className="max-w-4xl mx-auto text-center relative z-10">
          <RevealOnScroll>
            <h2 className="text-4xl md:text-5xl font-black text-white mb-8">Let's Build Something Great Together</h2>
            <p className="text-brand-light text-xl mb-12 max-w-2xl mx-auto opacity-90">
              Open for collaboration on robotics research projects, IEEE events, and innovative technical ventures.
            </p>
            <div className="glass bg-white/10 dark:bg-white/5 border-white/20 p-10 rounded-[3rem] shadow-2xl backdrop-blur-2xl">
              <h3 className="text-2xl font-bold text-white mb-8">Direct Contact</h3>
              <div className="flex flex-col md:flex-row items-center justify-center gap-8 mb-10">
                <a href={`mailto:${data.profile.email}`} className="flex items-center gap-3 text-white text-lg font-medium hover:scale-105 transition-transform">
                  <div className="w-12 h-12 bg-white/20 rounded-xl flex items-center justify-center">
                    <i className="fas fa-envelope"></i>
                  </div>
                  {data.profile.email}
                </a>
              </div>
              <div className="flex justify-center gap-6">
                {[
                  { icon: 'fa-github', link: data.profile.github },
                  { icon: 'fa-linkedin', link: data.profile.linkedin }
                ].map((social, i) => (social.link && (
                  <a key={i} href={social.link} target="_blank" className="w-14 h-14 bg-white text-brand rounded-2xl flex items-center justify-center text-2xl hover:-translate-y-2 transition-transform shadow-xl">
                    <i className={`fab ${social.icon}`}></i>
                  </a>
                )))}
              </div>
            </div>
          </RevealOnScroll>
        </div>
      </section>

      {/* Footer */}
      <footer className="py-10 text-center border-t border-slate-200 dark:border-slate-800">
        <p className="text-slate-500 dark:text-slate-400 text-sm">
          &copy; {new Date().getFullYear()} Md Atik Sheikh. Built with React & Tailwind CSS. <br className="md:hidden" />
          <a href="/admin/index.html" className="text-brand hover:underline mt-2 inline-block">Admin Login</a>
        </p>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

