import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { 
  Profile, 
  ResearchInterest, 
  Experience, 
  Project, 
  SkillCategory, 
  Achievement, 
  PortfolioData 
} from './types';

// Fallback data
const FALLBACK_DATA: PortfolioData = {
  profile: {
    name: "Md Atik Sheikh",
    position: "Secretary, IEEE RAS RUSB",
    university: "University of Rajshahi",
    bio: "Passionate researcher focused on Robotics and Automation. Leader at IEEE Robotics and Automation Society Student Branch, dedicated to fostering innovation and technical excellence.",
    image: "https://picsum.photos/seed/atik/400/400",
    email: "atik.sheikh@ieee.org",
    github: "https://github.com",
    linkedin: "https://linkedin.com"
  },
  research: [
    { title: "Robotics & Automation", icon: "fa-robot", description: "Exploring autonomous control systems and swarm robotics." },
    { title: "Artificial Intelligence", icon: "fa-brain", description: "Applying deep learning techniques to computer vision problems." }
  ],
  experience: [
    { role: "Secretary", organization: "IEEE RAS RUSB", period: "2023 - Present", description: "Leading administrative operations and coordinating workshops.", type: "leadership" }
  ],
  projects: [
    { title: "Autonomous Explorer Drone", description: "A customized hexacopter for indoor autonomous navigation.", image: "https://picsum.photos/seed/drone/800/450", tags: ["ROS", "Python"], github: "https://github.com" }
  ],
  skills: [
    { category: "Languages", items: ["C++", "Python", "JavaScript"] }
  ],
  achievements: [
    { title: "Best Student Volunteer", date: "2023", issuer: "IEEE Bangladesh Section" }
