};

// --- Components ---

const RevealOnScroll: React.FC<{ children: React.ReactNode; className?: string }> = ({ children, className = "" }) => {
  const ref = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => { if (entry.isIntersecting) entry.target.classList.add('active'); });
    }, { threshold: 0.1 });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);
  return <div ref={ref} className={`reveal ${className}`}>{children}</div>;
};

const SectionTitle: React.FC<{ title: string; subtitle?: string }> = ({ title, subtitle }) => (
  <div className="mb-12 text-center">
    <h2 className="text-3xl md:text-4xl font-extrabold text-slate-900 dark:text-white mb-4">{title}</h2>
    {subtitle && <p className="text-brand font-semibold tracking-wider uppercase text-sm">{subtitle}</p>}
    <div className="w-20 h-1.5 bg-brand mx-auto mt-4 rounded-full"></div>
  </div>
);

const AIChatBot: React.FC<{ data: PortfolioData }> = ({ data }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'bot', text: string }[]>([
    { role: 'bot', text: `Hi! I'm Md Atik Sheikh's AI assistant. Ask me anything about his research or leadership at IEEE!` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const systemPrompt = `You are a professional AI Assistant for Md Atik Sheikh.
      Context:
      - Name: ${data.profile.name}
      - Position: ${data.profile.position} at ${data.profile.university}
      - Bio: ${data.profile.bio}
      - Research: ${JSON.stringify(data.research)}
      - Experience: ${JSON.stringify(data.experience)}
      - Projects: ${JSON.stringify(data.projects)}
      - Skills: ${JSON.stringify(data.skills)}
      - Achievements: ${JSON.stringify(data.achievements)}

      Instructions:
      1. Be concise, polite, and professional.
      2. If asked about contact info, mention email: ${data.profile.email}.
      3. If asked about something not in the context, politely say you don't have that specific information.
      4. Use Markdown for formatting.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: userMsg,
        config: { systemInstruction: systemPrompt }
      });

      setMessages(prev => [...prev, { role: 'bot', text: response.text || "I'm sorry, I couldn't process that." }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'bot', text: "Sorry, I'm having trouble connecting to my brain right now." }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100] font-sans">
      {!isOpen ? (
        <button 
          onClick={() => setIsOpen(true)}
          className="w-16 h-16 bg-brand text-white rounded-full shadow-2xl flex items-center justify-center text-2xl hover:scale-110 transition-transform animate-bounce"
        >
          <i className="fas fa-comment-dots"></i>
        </button>
      ) : (
        <div className="w-[90vw] md:w-96 h-[500px] glass rounded-3xl shadow-2xl flex flex-col overflow-hidden border border-brand/20">
          <div className="bg-brand p-4 text-white flex justify-between items-center">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-white/20 rounded-lg flex items-center justify-center"><i className="fas fa-robot"></i></div>
              <span className="font-bold">AI Assistant</span>
            </div>
            <button onClick={() => setIsOpen(false)}><i className="fas fa-times"></i></button>
          </div>
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                  m.role === 'user' 
                  ? 'bg-brand text-white rounded-tr-none' 
                  : 'bg-slate-100 dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-tl-none'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-slate-100 dark:bg-slate-800 p-3 rounded-2xl animate-pulse text-xs">AI is thinking...</div>
              </div>
            )}
          </div>
          <div className="p-4 border-t border-slate-200 dark:border-slate-800 bg-white/50 dark:bg-slate-900/50">
            <div className="flex gap-2">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Ask me anything..."
                className="flex-1 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-brand"
              />
              <button 
                onClick={handleSend}
                className="bg-brand text-white w-10 h-10 rounded-xl flex items-center justify-center hover:bg-brand-dark transition-colors"
              >
                <i className="fas fa-paper-plane"></i>
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// --- Main App ---

const App: React.FC = () => {
  const [data, setData] = useState<PortfolioData>(FALLBACK_DATA);
  const [darkMode, setDarkMode] = useState(true);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (darkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [darkMode]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const fetchFile = async (path: string) => {
          const res = await fetch(path);
          if (!res.ok) throw new Error(`404: ${path}`);
          return res.json();
        };

        const [profile, research, experience, projects, skills, achievements] = await Promise.all([
          fetchFile('/content/profile.json'),
          fetchFile('/content/research.json'),
          fetchFile('/content/experience.json'),
          fetchFile('/content/projects.json'),
          fetchFile('/content/skills.json'),
          fetchFile('/content/achievements.json'),
        ]);

        setData({ 
          profile, 
          research: Array.isArray(research) ? research : (research.areas || []), 
          experience: Array.isArray(experience) ? experience : (experience.experiences || []), 
          projects: Array.isArray(projects) ? projects : (projects.projects || []), 
          skills: Array.isArray(skills) ? skills : (skills.categories || []), 
          achievements: Array.isArray(achievements) ? achievements : (achievements.awards || []) 
        });
      } catch (err) {
        console.warn("Using fallback data.");
        setData(FALLBACK_DATA);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="h-screen w-screen flex items-center justify-center bg-slate-50 dark:bg-slate-950">
