const RevealOnScroll: React.FC<{ children: React.ReactNode; className?: string }> = ({ children, className = "" }) => {
  const ref = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => { if (entry.isIntersecting) entry.target.classList.add('active'); });
    }, { threshold: 0.1 });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);
  return <div ref={ref} className={`reveal ${className}`}>{children}</div>;
};

const SectionTitle: React.FC<{ title: string; subtitle?: string }> = ({ title, subtitle }) => (
  <div className="mb-12 text-center">
    <h2 className="text-3xl md:text-4xl font-extrabold text-slate-900 dark:text-white mb-4">{title}</h2>
    {subtitle && <p className="text-brand font-semibold tracking-wider uppercase text-sm">{subtitle}</p>}
    <div className="w-20 h-1.5 bg-brand mx-auto mt-4 rounded-full"></div>
  </div>
);

const AIChatBot: React.FC<{ data: PortfolioData }> = ({ data }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'bot', text: string }[]>([
    { role: 'bot', text: `Hi! I'm Md Atik Sheikh's AI assistant. Ask me anything about his research or leadership at IEEE!` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const systemPrompt = `You are a professional AI Assistant for Md Atik Sheikh.
      Your goal is to answer questions about him based on this data:
      - Name: ${data.profile.name}
      - Position: ${data.profile.position} at ${data.profile.university}
      - Bio: ${data.profile.bio}
      - Research Areas: ${data.research.map(r => r.title).join(', ')}
      - Top Projects: ${data.projects.map(p => p.title).join(', ')}
      - Skills: ${data.skills.map(s => s.category + ': ' + s.items.join(', ')).join(' | ')}

      Instructions:
      1. Be concise, professional, and friendly.
      2. If asked for contact info, provide ${data.profile.email}.
      3. Use simple markdown (bold, lists) where appropriate.
      4. If you don't know the answer, say "I don't have that information right now, but you can email Md Atik Sheikh directly."`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: userMsg,
        config: { systemInstruction: systemPrompt }
      });

      setMessages(prev => [...prev, { role: 'bot', text: response.text || "I'm sorry, I couldn't generate a response." }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'bot', text: "I'm having trouble connecting to my knowledge base. Please try again later." }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100] font-sans">
      {!isOpen ? (
        <button 
          onClick={() => setIsOpen(true)}
          className="w-16 h-16 bg-brand text-white rounded-full shadow-2xl flex items-center justify-center text-2xl hover:scale-110 transition-transform animate-bounce border-4 border-white dark:border-slate-800"
        >
          <i className="fas fa-robot"></i>
        </button>
      ) : (
        <div className="w-[90vw] md:w-96 h-[500px] glass rounded-3xl shadow-2xl flex flex-col overflow-hidden border border-brand/20">
          <div className="bg-brand p-4 text-white flex justify-between items-center">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-white/20 rounded-lg flex items-center justify-center"><i className="fas fa-microchip"></i></div>
              <div>
                <p className="font-bold text-sm leading-tight">Atik's AI</p>
                <p className="text-[10px] opacity-80">Online & Ready</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:rotate-90 transition-transform p-1">
              <i className="fas fa-times"></i>
            </button>
          </div>
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-white/30 dark:bg-slate-900/30">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm shadow-sm ${
                  m.role === 'user' 
                  ? 'bg-brand text-white rounded-tr-none' 
                  : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-tl-none border border-slate-200 dark:border-slate-700'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-white dark:bg-slate-800 p-3 rounded-2xl animate-pulse text-[10px] text-slate-400">Assistant is typing...</div>
              </div>
            )}
          </div>
          <div className="p-4 border-t border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80">
            <div className="flex gap-2">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Ask me about his research..."
                className="flex-1 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-brand dark:text-white"
              />
              <button 
                onClick={handleSend}
                disabled={isTyping}
                className="bg-brand text-white w-10 h-10 rounded-xl flex items-center justify-center hover:bg-brand-dark transition-colors disabled:opacity-50"
              >
                <i className="fas fa-paper-plane"></i>
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

